import React from 'react';
import "./Menu.css";
import "nes.css/css/nes.min.css";

let displayMenu = false;

const Menu = ({displayMenu}) => {
	if (!displayMenu) {
    return <label>
						<a onClick="{displayMenu = true}">
							<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
							<span>Start</span>
						</a>
					</label>
	} else {
			return (
				<div className=""></div>
			)
	}
}

export default Menu;
